1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type Step = { op: "quote"; items: Item[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const itemBasePremium = (item: Item): number => {
9	  if (item.type === "sword") return 100;
10	  if (item.type === "amulet") return 60;
11	  return 0;
12	};
13	
14	const quotePremium = (items: Item[]): number => {
15	  const basePremium = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
16	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
17	  return Math.ceil(basePremium + firstInsurance) + PROCESSING_FEE;
18	};
19	
20	export const runScenario = (scenario: Scenario): unknown => {
21	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
22	  return { results };
23	};
